import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import avatar from '../components/static/HedMayner.png'


const MePageWrapper = styled.div `
width:90%;
margin:0 auto;
`

const MeHeader = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
`

const MeBody = styled.div ``

const Avatar = styled.div `
border-radius:50%;
width:150px;
height:150px;
background-image:url(${avatar});
background-position:center;
background-size:cover;
`

const LeftPart = styled.div `
display:flex;
justify-content:center;
align-items:center;
margin:40px 0;
`

const Username = styled.div `
margin:0 40px;
`

const TransactionWrapper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Transaction = styled.div `
font-size:1.2rem;
font-weight:800;
`

const TransactionWord = styled.div `
font-size:0.8rem;
`

const FollowersWrappper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Followers = styled.div `
font-size:1.2rem;
font-weight:800;
`

const FollowersWord = styled.div `
font-size:0.8rem;
`

const EditProfile = styled.div ``


export default function Me () {
	return (
		<>
			<Header />
			<Navbar />
			<MePageWrapper>
				<MeHeader>
					<LeftPart>
						<Avatar />
						<Username>NoahHong</Username>
						<TransactionWrapper>
							<Transaction>3</Transaction>
							<TransactionWord>Transactions</TransactionWord>
						</TransactionWrapper>
						<FollowersWrappper>
							<Followers>3</Followers>
							<FollowersWord>Transactions</FollowersWord>
						</FollowersWrappper>
					</LeftPart>
					<EditProfile>Edit Profile</EditProfile>
				</MeHeader>
				<MeBody>

				</MeBody>
			</MePageWrapper>
		</>
	)
}
